script:
frappe.ui.form.on("Hostel", {
    refresh(frm) {
        if (frm.is_new()) return;

        frm.add_custom_button("Generate Monthly Fees", function() {
            frappe.prompt(
                [
                    {
                        fieldname: "month", label: "Month", fieldtype: "Select",
                        options: "January\nFebruary\nMarch\nApril\nMay\nJune\nJuly\nAugust\nSeptember\nOctober\nNovember\nDecember",
                        reqd: 1
                    },
                    {
                        fieldname: "academic_year", label: "Academic Year", fieldtype: "Link",
                        options: "Academic Year", reqd: 1
                    }
                ],
                (values) => {
                    frappe.call({
                        method: "generate_monthly_hostel_fees",
                        args: {
                            hostel: frm.doc.name,
                            month: values.month,
                            academic_year: values.academic_year
                        },
                        freeze: true,
                        freeze_message: "Generating fees...",
                        callback: (r) => {
                            frappe.msgprint(r.message);
                        }
                    });
                },
                "Generate Monthly Fees"
            );
        }, "Create");
    }
});
